function Invoke-AfkProgBar { [CmdletBinding()] param([switch]$NoKeepAlive); $pingEvery = 60; $supportsStyle = $null -ne $PSStyle; if ($supportsStyle) { $origStyle = $PSStyle.Progress.Style; $origView = $PSStyle.Progress.View; $PSStyle.Progress.Style = "$([char]27)[44m$([char]27)[97m"; $PSStyle.Progress.View = 'Classic' }; $wshell = if (-not $NoKeepAlive) { New-Object -ComObject WScript.Shell } else { $null }; $lastPing = Get-Date; try { while ($true) { for ($p = 0; $p -le 100; $p += 2) { Write-Progress -Activity 'AFK - keeping session warm' -Status "Cycling... $p%" -PercentComplete $p; if (-not $NoKeepAlive -and ((Get-Date) - $lastPing).TotalSeconds -ge $pingEvery) { if (Get-Process -Name 'ms-teams','Teams' -ErrorAction SilentlyContinue) { $wshell.SendKeys('{SCROLLLOCK}'); Start-Sleep -Milliseconds 80; $wshell.SendKeys('{SCROLLLOCK}') }; $lastPing = Get-Date }; Start-Sleep -Milliseconds 120 } } } finally { Write-Progress -Activity 'AFK' -Completed; if ($supportsStyle) { $PSStyle.Progress.Style = $origStyle; $PSStyle.Progress.View = $origView }; Write-Host 'AFK progress bar stopped.' } }
